import React, { useEffect, useState } from "react";
import axios from "axios";
import { Calendar, Spin, message, Card } from "antd";
import { addDays, isBefore, isSameDay, format } from "date-fns";
import { ToastContainer } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";
import "antd/dist/reset.css";
import "../../../assets/style.css";

function FacultySchedulePage() {
  const [courses, setCourses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [classDates, setClassDates] = useState({});

  const facultyUser = JSON.parse(localStorage.getItem("user") || "{}");
  const facultyId = facultyUser?._id;

  // ---------------- Fetch Courses ----------------
  useEffect(() => {
    const fetchCourses = async () => {
      try {
        const facultyEmail = facultyUser?.email || facultyUser?.universityEmail;
        if (!facultyEmail) {
          setCourses([]);
          setLoading(false);
          return;
        }

        const resCourses = await axios.get(
          "http://localhost:65000/api/faculty-courses/courses",
          { params: { universityEmail: facultyEmail } }
        );

        const activeCourses = (resCourses.data.courses || []).filter(
          (c) => c.teachingStatus === "in-progress" && c.isActive
        );

        // Fetch course slots
        for (const course of activeCourses) {
          try {
            const resSlots = await axios.get(
              "http://localhost:65000/api/faculty-timetable/course-slots",
              {
                params: {
                  facultyId,
                  courseCode: course.courseCode,
                  batchId: course.batchId,
                  sectionName: course.sectionName,
                },
              }
            );
            course.timeSlots = resSlots.data.timeSlots || [];
          } catch {
            course.timeSlots = [];
          }
        }

        setCourses(activeCourses);
      } catch (err) {
        console.error(err);
        message.error("Failed to load courses");
      } finally {
        setLoading(false);
      }
    };

    fetchCourses();
  }, [facultyId]);

  // ---------------- Generate All Class Dates ----------------
  useEffect(() => {
    if (!courses.length) return;

    const allDates = {};
    const dayMap = {
      Sunday: 0,
      Monday: 1,
      Tuesday: 2,
      Wednesday: 3,
      Thursday: 4,
      Friday: 5,
      Saturday: 6,
    };

    courses.forEach((course) => {
      if (!course.timeSlots || !course.semesterStartDate || !course.semesterEndDate)
        return;

      course.timeSlots.forEach((slot) => {
        const dayName = slot.day.charAt(0).toUpperCase() + slot.day.slice(1);
        const dayNum = dayMap[dayName];
        if (typeof dayNum !== "number") return;

        let current = new Date(course.semesterStartDate);
        const end = new Date(course.semesterEndDate);

        while (current <= end) {
          if (current.getDay() === dayNum) {
            const dateStr = `${current.getFullYear()}-${String(
              current.getMonth() + 1
            ).padStart(2, "0")}-${String(current.getDate()).padStart(2, "0")}`;

            if (!allDates[dateStr]) allDates[dateStr] = [];

            allDates[dateStr].push({
              courseCode: course.courseCode,
              courseName: course.courseName,
              sectionName: course.sectionName,
              startTime: slot.startTime,
              endTime: slot.endTime,
              room: slot.room,
            });
          }
          current = addDays(current, 1);
        }
      });
    });

    setClassDates(allDates);
  }, [courses]);

  // ---------------- Calendar Cell UI ----------------
  const dateCellRender = (value) => {
    const dateObj = value.toDate ? value.toDate() : new Date(value);

    const dateStr = `${dateObj.getFullYear()}-${String(dateObj.getMonth() + 1).padStart(
      2,
      "0"
    )}-${String(dateObj.getDate()).padStart(2, "0")}`;

    const today = new Date();
    const classes = classDates[dateStr] || [];
    if (!classes.length) return null;

    const isPast = isBefore(dateObj, today) && !isSameDay(dateObj, today);

    return (
      <div className="calendar-event-container">
        {classes.map((cls, i) => (
          <div key={i} className={`calendar-event ${isPast ? 'past-event' : 'upcoming-event'}`}>
            <div className="event-course-code">
              {cls.courseCode} ({cls.sectionName})
            </div>
            <div className="event-time">
              {cls.startTime} - {cls.endTime}
            </div>
            <div className="event-room">
              Room: {cls.room}
            </div>
          </div>
        ))}
      </div>
    );
  };

  // ---------------- UI ----------------
  return (
    <div className="add-batch container mt-5">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h2 className="add-batch-title mb-0">
          Semester Class Schedule
        </h2>
        <div className="calendar-legend">
          <span className="legend-item">
            <span className="legend-dot upcoming-dot"></span>
            Upcoming Classes
          </span>
          <span className="legend-item">
            <span className="legend-dot past-dot"></span>
            Past Classes
          </span>
        </div>
      </div>

      <Card className="calendar-card">
        {loading ? (
          <div className="text-center py-5">
            <Spin size="large" />
            <p className="mt-3">Loading schedule...</p>
          </div>
        ) : courses.length === 0 ? (
          <div className="text-center py-5">
            <p>No active courses found for this semester.</p>
          </div>
        ) : (
          <div className="calendar-wrapper">
            <Calendar
              dateCellRender={dateCellRender}
              fullscreen={false}
              className="custom-calendar"
            />
          </div>
        )}
      </Card>

      <ToastContainer position="top-right" />

      <style jsx>{`
        .calendar-card {
          background: white;
          border-radius: 8px;
          box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
          border: 1px solid #e8e8e8;
        }

        .calendar-wrapper {
          padding: 10px;
        }

        .custom-calendar .ant-picker-calendar {
          background: white;
        }

        .custom-calendar .ant-picker-calendar-header {
          padding: 16px;
          border-bottom: 1px solid #e8e8e8;
        }

        .custom-calendar .ant-picker-calendar .ant-picker-panel {
          border: none;
        }

        .calendar-legend {
          display: flex;
          gap: 20px;
        }

        .legend-item {
          display: flex;
          align-items: center;
          font-size: 14px;
          color: #666;
        }

        .legend-dot {
          width: 12px;
          height: 12px;
          border-radius: 50%;
          margin-right: 8px;
        }

        .upcoming-dot {
          background-color: #c8f7c5;
          border: 1px solid #51cf66;
        }

        .past-dot {
          background-color: #ffd6d6;
          border: 1px solid #ff6b6b;
        }

        .calendar-event-container {
          max-height: 120px;
          overflow-y: auto;
        }

        .calendar-event {
          padding: 8px;
          margin-bottom: 8px;
          border-radius: 4px;
          font-size: 12px;
          line-height: 1.4;
        }

        .upcoming-event {
          background-color: #e6f7ff;
          border: 1px solid #91d5ff;
          color: #0050b3;
        }

        .past-event {
          background-color: #fff2e8;
          border: 1px solid #ffbb96;
          color: #d46b08;
        }

        .event-course-code {
          font-weight: 600;
          margin-bottom: 2px;
        }

        .event-time {
          font-size: 11px;
          margin-bottom: 2px;
        }

        .event-room {
          font-size: 11px;
          font-weight: 500;
        }

        @media (max-width: 768px) {
          .calendar-legend {
            flex-direction: column;
            gap: 8px;
          }

          .custom-calendar .ant-picker-calendar-header {
            flex-direction: column;
            gap: 10px;
          }
        }
      `}</style>
    </div>
  );
}

export default FacultySchedulePage;
